// Parse and extract UTM parameters and attribution data
const data = $input.item.json;

// Extract UTM parameters
const url = new URL(data.page_url || 'https://example.com');
const params = url.searchParams;

const utmSource = params.get('utm_source') || data.utm_source || 'direct';
const utmMedium = params.get('utm_medium') || data.utm_medium || 'none';
const utmCampaign = params.get('utm_campaign') || data.utm_campaign || '';
const utmTerm = params.get('utm_term') || data.utm_term || '';
const utmContent = params.get('utm_content') || data.utm_content || '';

// Extract referrer information
const referrer = data.referrer || data.http_referer || '';
let referrerDomain = 'direct';
let referrerPath = '';

if (referrer && referrer !== '') {
  try {
    const referrerUrl = new URL(referrer);
    referrerDomain = referrerUrl.hostname.replace('www.', '');
    referrerPath = referrerUrl.pathname;
  } catch (e) {
    referrerDomain = 'unknown';
  }
}

// Determine channel based on source and medium
function determineChannel(source, medium, referrer) {
  // Direct traffic
  if (source === 'direct' && medium === 'none') {
    return 'Direct';
  }

  // Organic search
  const searchEngines = ['google', 'bing', 'yahoo', 'duckduckgo', 'baidu'];
  if (medium === 'organic' || searchEngines.some(se => referrer.includes(se))) {
    return 'Organic Search';
  }

  // Paid search
  if (medium === 'cpc' || medium === 'ppc' || medium === 'paid') {
    return 'Paid Search';
  }

  // Social media
  const socialPlatforms = ['facebook', 'twitter', 'linkedin', 'instagram', 'youtube', 'tiktok', 'pinterest'];
  if (medium === 'social' || socialPlatforms.some(sp => source.includes(sp) || referrer.includes(sp))) {
    return 'Social Media';
  }

  // Email
  if (medium === 'email' || source === 'newsletter' || source === 'email') {
    return 'Email';
  }

  // Referral
  if (medium === 'referral' || (referrer && referrer !== '')) {
    return 'Referral';
  }

  return 'Other';
}

const channel = determineChannel(utmSource, utmMedium, referrerDomain);

// Extract device and browser info
const userAgent = data.user_agent || '';
let deviceType = 'desktop';
let browser = 'unknown';
let os = 'unknown';

if (userAgent) {
  // Detect device
  if (/mobile|android|iphone|ipad|ipod/i.test(userAgent)) {
    deviceType = /ipad/i.test(userAgent) ? 'tablet' : 'mobile';
  } else if (/tablet/i.test(userAgent)) {
    deviceType = 'tablet';
  }

  // Detect browser
  if (/chrome/i.test(userAgent) && !/edge|edg/i.test(userAgent)) {
    browser = 'Chrome';
  } else if (/safari/i.test(userAgent) && !/chrome/i.test(userAgent)) {
    browser = 'Safari';
  } else if (/firefox/i.test(userAgent)) {
    browser = 'Firefox';
  } else if (/edge|edg/i.test(userAgent)) {
    browser = 'Edge';
  }

  // Detect OS
  if (/windows/i.test(userAgent)) {
    os = 'Windows';
  } else if (/mac/i.test(userAgent)) {
    os = 'macOS';
  } else if (/linux/i.test(userAgent)) {
    os = 'Linux';
  } else if (/android/i.test(userAgent)) {
    os = 'Android';
  } else if (/ios|iphone|ipad/i.test(userAgent)) {
    os = 'iOS';
  }
}

// Generate session ID if not provided
const sessionId = data.session_id || `session_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

return {
  json: {
    // Attribution data
    session_id: sessionId,
    user_id: data.user_id || null,
    visitor_id: data.visitor_id || null,

    // UTM parameters
    utm_source: utmSource,
    utm_medium: utmMedium,
    utm_campaign: utmCampaign,
    utm_term: utmTerm,
    utm_content: utmContent,

    // Referrer data
    referrer: referrer,
    referrer_domain: referrerDomain,
    referrer_path: referrerPath,

    // Calculated channel
    channel: channel,

    // Page data
    page_url: data.page_url || '',
    page_path: new URL(data.page_url || 'https://example.com').pathname,
    page_title: data.page_title || '',

    // Device data
    device_type: deviceType,
    browser: browser,
    os: os,
    user_agent: userAgent,

    // Geo data (if provided)
    country: data.country || null,
    region: data.region || null,
    city: data.city || null,

    // Timestamp
    timestamp: new Date().toISOString(),

    // Lead conversion flag (if this is a lead)
    is_lead: data.is_lead || false,
    lead_id: data.lead_id || null
  }
};

